import React, { useState } from 'react';
import LeadList from './LeadList';
import LeadDetail from './LeadDetail';
import AddLead from './AddLead';

const Dashboard = ({ leads, onLogout, fetchLeads }) => {
  const [selectedLead, setSelectedLead] = useState(null);
  const [showAddLead, setShowAddLead] = useState(false);

  const handleUpdateLeadSuccess = async () => {
    // Refresh leads and update selectedLead with fresh data
    await fetchLeads();
  };

  return (
    <div className="dashboard">
      <header>
        <h1>Mini CRM Dashboard</h1>
        <button onClick={() => setShowAddLead(true)} className="btn-add-lead">+ Add Lead</button>
        <button onClick={onLogout}>Logout</button>
      </header>
      <div className="content">
        <LeadList leads={leads} onSelectLead={setSelectedLead} />
        {selectedLead && <LeadDetail lead={selectedLead} fetchLeads={fetchLeads} />}
      </div>
      {showAddLead && <AddLead fetchLeads={fetchLeads} onClose={() => setShowAddLead(false)} />}
    </div>
  );
};

export default Dashboard;
